(()=>{document.addEventListener("DOMContentLoaded",()=>{let t=document.getElementById("note"),n=document.getElementById("save"),o=document.getElementById("status");chrome.storage.local.get(["quickNote"],e=>{t.value=e.quickNote||""}),n.addEventListener("click",()=>{let e=t.value;chrome.storage.local.set({quickNote:e},()=>{o.textContent="Note saved!",setTimeout(()=>{o.textContent=""},1500)})})});})();
